ml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"beta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=729478\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:327:\"¡WordPress 6.9 Beta 2 ya está lista para probar! Esta versión beta de WordPress está en desarrollo . No instales, ejecutes ni pruebes esta versión de WordPress en sitios web en producción o esenciales. En su lugar, haz pruebas con la Beta 2 en un servidor y sitio de pruebas. Puedes probar WordPress 6.9 Beta 2 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5792:\"\n<p class=\"wp-block-paragraph\">¡WordPress 6.9 Beta 2 ya está lista para probar!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versión beta de WordPress está en desarrollo</strong> . No instales, ejecutes ni pruebes esta versión de WordPress en sitios web en producción o esenciales. En su lugar, haz pruebas con la Beta 2 en un servidor y sitio de pruebas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Puedes probar WordPress 6.9 Beta 2 de cualquiera de las siguientes maneras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instala y activa el plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> en una instalación de WordPress. (Selecciona el canal «Bleeding edge» y la transmisión «Beta/RC Only»).</td></tr><tr><td><strong>Descarga directa</strong></td><td>Descarga la <a href=\"https://wordpress.org/wordpress-6.9-beta2.zip\">versión Beta 2 (zip)</a> e instálela en un sitio web de WordPress.</td></tr><tr><td><strong>Línea de comandos</strong></td><td>Utiliza este comando <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> :<br><code>wp core update --version=6.9-beta2</code></td></tr><tr><td><strong>Zona de juegos de WordPress</strong></td><td>Usa la&nbsp;<a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instancia de WordPress Playground 6.9 Beta 2</a>&nbsp;para probar el software directamente en tu navegador. No requiere configuración: ¡solo haz clic y listo!&nbsp;</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">La fecha de lanzamiento final programada para WordPress 6.9 es <strong>el 2 de diciembre de 2025.</strong> El <a href=\"https://make.wordpress.org/core/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">calendario completo de lanzamientos se puede consultar aquí</a> . tu ayuda en las pruebas de las versiones Beta y RC es vital para que esta versión sea lo más estable y potente posible. Consulta el <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para obtener más información <a href=\"https://make.wordpress.org/core/tag/6-9/\">sobre la versión 6.9</a> en las próximas semanas. ¡Gracias a todos los que contribuyen con las pruebas! </p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Ponte al día con las novedades de WordPress 6.9</strong> : lee el <a href=\"https://make.wordpress.org/core/2025/10/21/wordpress-6-9-beta-1/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la versión Beta 1</a> para conocer los detalles y aspectos destacados.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo probar esta versión</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Tu ayuda para probar la versión Beta 2 de WordPress 6.9 es clave para garantizar que todo en la versión sea óptimo. Si bien probar el proceso de actualización es esencial, probar nuevas funciones es igualmente importante. Esta <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">guía detallada</a> te guiará en el proceso de prueba de funcionalidades en WordPress 6.9.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Si encuentras algún problema, infórmalo al <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">área Alfa/Beta</a> de los foros de soporte o directamente en el <a href=\"https://core.trac.wordpress.org/newticket\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Trac</a> si te sientes cómodo escribiendo un informe de errores reproducible. También puedes comparar tu problema con una lista de <a href=\"https://core.trac.wordpress.org/tickets/major\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">errores conocidos</a> .</p>\n\n\n\n<p class=\"wp-block-paragraph\">¿Te interesa probar las versiones en general? Sigue las <a href=\"https://make.wordpress.org/test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">iniciativas de pruebas en Make Core</a> y únete al <a href=\"https://wordpress.slack.com/messages/core-test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">canal #core-test</a> en <a href=\"https://wordpress.slack.com/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\"> el Slack de Making WordPress</a> .</p>\n\n\n\n<h2 class=\"wp-block-heading\">Actualizaciones y aspectos destacados de la versión Beta 2</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9 Beta 2 contiene más de 33 actualizaciones y correcciones del editor desde el lanzamiento de la versión Beta 1, incluidos 28 tiques para el núcleo de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cada ciclo beta se centra en la corrección de errores; con tu ayuda durante las pruebas, se irán añadiendo más. Puedes consultar la información técnica de todos los problemas solucionados desde la Beta 1 en estos enlaces:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.9?since=2025-10-22&amp;until=2025-10-28\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Commits a GitHub para la versión 6.9</a> desde el 21 de octubre de 2025</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=10%2F22%2F2025..10%2F28%2F2025&amp;milestone=6.9&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Tiques del Trac cerrados</a> desde el 21 de octubre de 2025</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Un haiku de la Beta 2</h2>\n\n\n\n<pre class=\"wp-block-verse\"><em>Vuelve el rocío de la mañana,</em>\n<em>Los pequeños arreglos florecen en silencio.</em>\n<em>El código encuentra su equilibrio.</em></pre>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://es.wordpress.org/2025/10/28/wordpress-6-9-beta-2/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"729478\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:30:\"https://es.wordpress.org/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096054\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Thu, 26 Feb 2026 13:35:43 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Thu, 26 Feb 2026 07:16:45 GMT\";s:4:\"link\";s:61:\"<https://es.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}}s:5:\"build\";i:1727736619;s:21:\"cache_expiration_time\";i:1772156143;s:23:\"__cache_expiration_time\";i:1772156143;}','off'),
