(17,'Litigation Finance — Financiación de litigios estratégicos a nivel internacional','Litigation Finance — Strategic litigation funding at the international level',2,0,5),
(18,'Derecho Global e Inversión — Asesoría M&amp;A transfronteriza y estructuración societaria internacional','Global Law and Investment — Cross-border M&amp;A advisory and international corporate structuring',2,0,6),
(19,'Tokenización de Activos Inmobiliarios — Proyecto DORA Compliance','Real Estate Asset Tokenization — DORA Compliance Project',2,0,7),
(20,'Asesoramos a un fondo de inversión europeo en la estructuración legal y técnica para la tokenización de una cartera inmobiliaria valorada en','We advised a European investment fund on the legal and technical structuring for the tokenization of a real estate portfolio valued at',2,0,8),
(21,'45 millones de euros','45 million euros',2,0,9),
(22,'. El proyecto requirió el cumplimiento simultáneo de MiCA, DORA y las regulaciones locales de tres jurisdicciones diferentes.','. The project required simultaneous compliance with MiCA, DORA, and local regulations across three different jurisdictions.',2,0,10),
(23,'Resultado: Aprobación regulatoria en 4 meses, 30% menos del tiempo estimado inicialmente.','Result: Regulatory approval in 4 months, 30% less than initially estimated.',2,0,11),
